# RAG with two cached layers: system prompt + retrieved docs
response = client.messages.create(
    model="claude-opus-4-5",
    max_tokens=512,
    system=[
        # Layer 1: static instructions (cached longest)
        {
            "type": "text",
            "text": SYSTEM_INSTRUCTIONS,
            "cache_control": {"type": "ephemeral"},
        },
        # Layer 2: retrieved context for this query (may change per session)
        {
            "type": "text",
            "text": "\n".join(retrieved_docs),
            "cache_control": {"type": "ephemeral"},
        },
    ],
    messages=[{"role": "user", "content": question}],
)
